ul.li:
tgid = Thread Group ID (what userspace calls PID)
c
u64 pid_tgid = bpf_get_current_pid_tgid();
u32 thread_id = (u32)pid_tgid;        // Lower 32 bits
u32 process_id = pid_tgid >> 32;      // Upper 32 bits
// ALWAYS use thread_id for hash map keys!
bpf_map_update_elem(&start_times, &thread_id, &start, BPF_ANY);
